mapper.update:
UPDATE device_unit
production_line_id = #{productionLineId}, unit_code = #{unitCode}, unit_name = #{unitName}, creator_id = #{creatorId}, updated_at = #{updateAt},
WHERE id = #{id}

mapper.select:
SELECT du.id, du.production_line_id, du.unit_code, du.unit_name, du.creator_id, du.created_at AS createAt, du.updated_at AS updateAt, pl.line_name AS productionLineName, su.real_name AS creatorName, su.username AS creatorUsername FROM device_unit du LEFT JOIN production_line pl ON du.production_line_id = pl.id LEFT JOIN sys_user su ON du.creator_id = su.id
AND du.creator_id = #{creatorId}
AND du.production_line_id = #{productionLineId}
AND du.unit_code LIKE CONCAT('%', #{unitCode}, '%')
AND du.unit_name LIKE CONCAT('%', #{unitName}, '%')
ORDER BY du.id DESC

SELECT id, production_line_id, unit_code, unit_name, creator_id, created_at AS createAt, updated_at AS updateAt FROM device_unit
AND production_line_id = #{productionLineId}
AND unit_code = #{unitCode}

